import{_ as a,o as i,c as o,a2 as e}from"./chunks/framework.7OsLnTMM.js";const f=JSON.parse('{"title":"权限","description":"","frontmatter":{},"headers":[],"relativePath":"guide/permissions.md","filePath":"guide/permissions.md","lastUpdated":null}'),r={name:"guide/permissions.md"};function t(n,l,h,p,s,d){return i(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h1><p>Autable 的权限系统围绕数据库 owner、角色、用户、workflow 和 form 资源展开。</p><h2 id="数据库-owner" tabindex="-1">数据库 owner <a class="header-anchor" href="#数据库-owner" aria-label="Permalink to &quot;数据库 owner&quot;">​</a></h2><p>数据库 owner 是最高权限主体。owner 可以：</p><ul><li>管理数据库权限。</li><li>删除字段。</li><li>删除记录。</li><li>删除 workflow。</li><li>删除 form。</li><li>查看历史记录。</li></ul><p>owner 设计上预留多个 owner 的扩展空间。</p><h2 id="表格权限" tabindex="-1">表格权限 <a class="header-anchor" href="#表格权限" aria-label="Permalink to &quot;表格权限&quot;">​</a></h2><p>表格权限分为三类。</p><h3 id="字段权限" tabindex="-1">字段权限 <a class="header-anchor" href="#字段权限" aria-label="Permalink to &quot;字段权限&quot;">​</a></h3><p>字段权限决定能看到和能写哪些字段：</p><ul><li>全部读。</li><li>全部写。</li><li>部分字段读写。</li><li>无权限。</li></ul><p>只有拥有全部字段写权限的用户才能新增字段。</p><h3 id="记录权限" tabindex="-1">记录权限 <a class="header-anchor" href="#记录权限" aria-label="Permalink to &quot;记录权限&quot;">​</a></h3><p>记录新增/删除是独立权限：</p><ul><li>可新增。</li><li>可删除。</li><li>可新增和删除。</li><li>无权限。</li></ul><p>更新记录字段依赖字段写权限。</p><h3 id="视图权限" tabindex="-1">视图权限 <a class="header-anchor" href="#视图权限" aria-label="Permalink to &quot;视图权限&quot;">​</a></h3><p>视图权限决定能读取或修改哪些视图：</p><ul><li>全部读。</li><li>全部写。</li><li>部分视图读写。</li><li>无权限。</li></ul><p>新增视图需要全部视图写权限。删除视图只有 owner 可以操作。</p><h2 id="workflow-权限" tabindex="-1">Workflow 权限 <a class="header-anchor" href="#workflow-权限" aria-label="Permalink to &quot;Workflow 权限&quot;">​</a></h2><p>workflow 支持：</p><ul><li>全部读。</li><li>全部写。</li><li>部分 workflow 读写。</li></ul><p>新增 workflow 需要全部 workflow 写权限。删除 workflow 只有数据库 owner 可以操作。</p><h2 id="form-权限" tabindex="-1">Form 权限 <a class="header-anchor" href="#form-权限" aria-label="Permalink to &quot;Form 权限&quot;">​</a></h2><p>form 权限和 workflow 类似：</p><ul><li>全部读。</li><li>全部写。</li><li>部分 form 读写。</li></ul><p>发布表单也不会绕过权限。打开表单、提交表单、写目标表都走登录用户权限。</p><h2 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h2><p>角色把一组 grants 绑定到成员上。成员可以是：</p><ul><li>user。</li><li>workflow。</li></ul><p>workflow 成为角色成员后，会继承角色授予的表格权限。</p><h2 id="互斥规则" tabindex="-1">互斥规则 <a class="header-anchor" href="#互斥规则" aria-label="Permalink to &quot;互斥规则&quot;">​</a></h2><p>“全部读写”和“部分读写”是互斥的。选择全部权限时，会清掉对应资源的部分权限；选择部分权限时，会清掉对应资源的全部权限。</p><p>这能避免一个角色同时拥有难以解释的全局权限和局部权限。</p>',35)])])}const w=a(r,[["render",t]]);export{f as __pageData,w as default};
